  1	import {
  2	  Dropdown,
  3	  DropdownItem,
  4	  DropdownList,
  5	  FormGroup,
  6	  MenuToggle,
  7	  MenuToggleElement,
  8	} from '@patternfly/react-core';
  9	import React from 'react';
 10	import { useTranslation } from 'react-i18next';
 11	import { useLocalStorage } from '../hooks/useLocalStorage';
 12	import { TestIds } from '../test-ids';
 13	
 14	const STORED_REFRESH_INTERVAL_KEY = 'logging-view-plugin.refresh-interval';
 15	
 16	const refreshIntervalOptions = [
 17	  { key: 'OFF_KEY', name: 'Refresh off', delay: 0 },
 18	  { key: '15s', name: '15 seconds', delay: 15 * 1000 },
 19	  { key: '30s', name: '30 seconds', delay: 30 * 1000 },
 20	  { key: '1m', name: '1 minute', delay: 60 * 1000 },
 21	  { key: '5m', name: '5 minutes', delay: 5 * 60 * 1000 },
 22	  { key: '15m', name: '15 minutes', delay: 15 * 60 * 1000 },
 23	  { key: '30m', name: '30 minutes', delay: 30 * 60 * 1000 },
 24	  { key: '1h', name: '1 hour', delay: 60 * 60 * 1000 },
 25	  { key: '2h', name: '2 hours', delay: 2 * 60 * 60 * 1000 },
 26	  { key: '1d', name: '1 day', delay: 24 * 60 * 60 * 1000 },
 27	];
 28	
 29	interface RefreshIntervalDropdownProps {
 30	  onRefresh?: () => void;
 31	  isDisabled?: boolean;
 32	}
 33	
 34	export const RefreshIntervalDropdown: React.FC<RefreshIntervalDropdownProps> = ({
 35	  onRefresh,
 36	  isDisabled = false,
 37	}) => {
 38	  const { t } = useTranslation('plugin__logging-view-plugin');
 39	
 40	  const [storedRefreshInterval, setStoredRefreshInterval] = useLocalStorage<{ interval: string }>(
 41	    STORED_REFRESH_INTERVAL_KEY,
 42	  );
 43	  const [isOpen, setIsOpen] = React.useState(false);
 44	  const [selectedIndex, setSelectedIndex] = React.useState<number>(
 45	    storedRefreshInterval && !isNaN(parseInt(storedRefreshInterval.interval, 10))
 46	      ? parseInt(storedRefreshInterval.interval, 10)
 47	      : 0,
 48	  );
 49	  const [delay, setDelay] = React.useState<number>(0);
 50	  const timer = React.useRef<NodeJS.Timer | null>(null);
 51	
 52	  const clearTimer = () => {
 53	    if (timer.current) {
 54	      clearInterval(timer.current);
 55	    }
 56	  };
 57	
 58	  const handleSelectedValue = (index: number) => () => {
 59	    setIsOpen(false);
 60	    setSelectedIndex(index);
 61	    const selectedDelay = refreshIntervalOptions[index].delay;
 62	    setDelay(selectedDelay);
 63	    setStoredRefreshInterval({ interval: index.toString(10) });
 64	  };
 65	
 66	  const restartTimer = (callRefreshImmediately = true) => {
 67	    clearTimer();
 68	
 69	    if (delay !== 0) {
 70	      if (callRefreshImmediately) {
 71	        onRefresh?.();
 72	      }
 73	      timer.current = setInterval(() => onRefresh?.(), delay);
 74	    }
 75	
 76	    return () => clearTimer();
 77	  };
 78	
 79	  React.useEffect(() => restartTimer(), [delay]);
 80	
 81	  // Avoid calling refresh immediately when onRefresh callback has changed
 82	  React.useEffect(() => restartTimer(false), [onRefresh]);
 83	
 84	  const toggleIsOpen = () => {
 85	    setIsOpen(!isOpen);
 86	  };
 87	
 88	  return (
 89	    <FormGroup fieldId="logs-refresh-interval" data-test={TestIds.RefreshIntervalDropdown}>
 90	      <Dropdown
 91	        isOpen={isOpen}
 92	        onSelect={() => setIsOpen(false)}
 93	        onOpenChange={(isOpenVal: boolean) => setIsOpen(isOpenVal)}
 94	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 95	          <MenuToggle
 96	            isDisabled={isDisabled}
 97	            ref={toggleRef}
 98	            onClick={toggleIsOpen}
 99	            isExpanded={isOpen}
100	          >
101	            {refreshIntervalOptions[selectedIndex].name}
102	          </MenuToggle>
103	        )}
104	      >
105	        <DropdownList>
106	          {refreshIntervalOptions.map(({ key, name }, index) => (
107	            <DropdownItem ouiaId={key} onClick={handleSelectedValue(index)} key={key}>
108	              {
109	                /*
110	                  t('plugin__logging-view-plugin~Refresh off')
111	                  t('plugin__logging-view-plugin~15 seconds')
112	                  t('plugin__logging-view-plugin~30 seconds')
113	                  t('plugin__logging-view-plugin~1 minute')
114	                  t('plugin__logging-view-plugin~5 minutes')
115	                  t('plugin__logging-view-plugin~15 minutes')
116	                  t('plugin__logging-view-plugin~30 minutes')
117	                  t('plugin__logging-view-plugin~1 hour')
118	                  t('plugin__logging-view-plugin~2 hours')
119	                  t('plugin__logging-view-plugin~1 day')
120	                */
121	                t(name)
122	              }
123	            </DropdownItem>
124	          ))}
125	        </DropdownList>
126	      </Dropdown>
127	    </FormGroup>
128	  );
129	};

